// 在此输入自定义内容// 在此输入自定义内容// 在此输入自定义内容
const generateFunction = () => {
    const config = options.useProjectId ? `{ ...fetchOptions, projectId: ${options.projectId} }` : "fetchOptions"
    let args = [];
    let key = [];
  const firstToLocaleUpperCase = (str) => {
    if (!str) return '';
    return str.charAt(0).toUpperCase() + str.slice(1);
  };
  const buildParams = () => {
    if (options.pathParams.length) {
      if (options.pathParams.length > 1) {
        args.push(`pathParams: Expand<${options.pathParamsType}>`);
        key.push('pathParams')
      } else {
        args.push(`${options.pathParams[0].name}: string`);
        key.push(options.pathParams[0].name)
      }
    }
    if (options.queryParams.length) {
      args.push(`params: Expand<${options.queryParamsType}>`);
      key.push('params')
    }

    args.push('fetchOptions: Expand<RequestInit> = {}');
    key.push('fetchOptions')
    const config = '_queryOptions?: object = {}'
    args.push(config);
    return args.join(', ');
  };
  const _buildParams = buildParams();
  if (['get', 'delete'].includes(options.apiMethod)) {
    const haveQueryParams = options.queryParams.length > 0;
    const allPath = haveQueryParams ? `[\`${options.apiPath}\`, params, fetchOptions]` : `[\`${options.apiPath}\`, fetchOptions]`;
    // queryOptions
    const a = `${'\n'}export const ${options.extraFunctionName} = (${_buildParams}) => {${'\n'}    return useQuery({queryKey: ${allPath}, queryFn: () => ${options.apiFunctionName}(${options.pathParams.length ? options.pathParams[0].name+', ' : ''}${haveQueryParams ? 'params, ' : ''}${config}), ..._queryOptions})${'\n'}}`;
    const b = `${'\n'}export const useOption${firstToLocaleUpperCase(options.apiFunctionName)} = (${_buildParams}) => {${'\n'}    return queryOptions({queryKey: ${allPath}, queryFn: () => ${options.apiFunctionName}(${options.pathParams.length ? options.pathParams[0].name+', ' : ''}${haveQueryParams ? 'params, ' : ''}${config}), ..._queryOptions})${'\n'}}`;
    return a+b
  } else {
    const useApiName = 'useMutation';
    return `${'\n'}export const ${options.extraFunctionName} = (_queryOptions?: object = {}) => {${'\n'}   return ${useApiName}({mutationFn: ${options.apiFunctionName}, ..._queryOptions})${'\n'}}`;
  }
};
generateFunction();
